"use client"

import { Badge } from "@/components/ui/badge"

interface BadgeCellProps {
  value: unknown
  variant?: "default" | "secondary" | "outline" | "destructive"
}

export function BadgeCell({
  value,
  variant = "outline",
}: BadgeCellProps) {
  return <Badge variant={variant}>{String(value ?? "")}</Badge>
}

"use client"

import { Button } from "@/components/ui/button"
import { Calendar } from "@/components/ui/calendar"
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover"
import { cn } from "@/lib/utils"
import { format } from "date-fns"
import * as React from "react"

interface DatepickerCellProps {
  value: Date | null
  onChange: (date: Date | null) => void
  dateFormat?: string
}

export function DatepickerCell({
  value,
  onChange,
  dateFormat = "yyyy-MM-dd",
}: DatepickerCellProps) {
  const [open, setOpen] = React.useState(false)

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button
          variant="outline"
          size="sm"
          className={cn(
            "h-8 w-32 justify-start text-left font-normal",
            !value && "text-muted-foreground",
          )}
        >
          {value ? format(value, dateFormat) : "Pick a date"}
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-auto p-0" align="start">
        <Calendar
          mode="single"
          selected={value ?? undefined}
          onSelect={(date) => {
            onChange(date ?? null)
            setOpen(false)
          }}
          initialFocus
        />
      </PopoverContent>
    </Popover>
  )
}

"use client"

import * as React from "react"
import { Input } from "@/components/ui/input"
import { SelectCell } from "./select-cell"
import { BadgeCell } from "./badge-cell"
import { DatepickerCell } from "./datepicker-cell"
import type {
  ColumnInputType,
  DynamicColumnDef,
  EditableInputProps,
} from "./../types/column.types"

interface EditableCellProps<TData, TValue>
  extends EditableInputProps<TData, TValue> {
  col: DynamicColumnDef<TData, TValue>
}

export function EditableCell<TData, TValue>({
  value: initialValue,
  row,
  rowId,
  accessorKey,
  onChange,
  col,
}: EditableCellProps<TData, TValue>) {
  const inputType: ColumnInputType = col.inputType ?? "text"
  const [value, setValue] = React.useState(initialValue)

  // Sync with external updates
  React.useEffect(() => {
    setValue(initialValue)
  }, [initialValue])

  // Helper: Commit change immediately on blur/select
  const onCommit = (newValue: unknown) => {
    setValue(newValue as TValue)
    onChange(newValue as TValue)
  }

  // Helper for type conversions
  const asString = (v: unknown): string => (v === null || v === undefined ? "" : String(v))
  const asDateOrNull = (v: unknown): Date | null => {
    if (!v) return null
    return v instanceof Date ? v : new Date(String(v))
  }

  switch (inputType) {
    case "text":
      return (
        <Input
          className="h-8 w-full min-w-[100px] border border-border"
          value={asString(value)}
          onChange={(e) => setValue(e.target.value as unknown as TValue)}
          onBlur={() => onCommit(value)}
        />
      )

    case "number":
      return (
        <Input
          type="number"
          className="h-8 w-full min-w-[80px]"
          value={asString(value)}
          onChange={(e) => setValue(e.target.value as unknown as TValue)}
          onBlur={() => onCommit(value)}
        />
      )

    case "select":
      return (
        <SelectCell
          value={value}
          options={col.selectOptions ?? []}
          onChange={onCommit}
        
        />
      )

    case "datepicker":
      return (
        <DatepickerCell
          value={asDateOrNull(value)}
          onChange={onCommit}
          dateFormat={col.dateFormat}
        />
      )

    case "badge":
      return <BadgeCell value={value} variant={col.badgeVariant} />

    case "custom":
      if (col.cellRenderInput) {
        return col.cellRenderInput({
          value,
          row,
          rowId,
          accessorKey,
          onChange: onCommit,
        })
      }
      return <span>{asString(value)}</span>

    default:
      return <span>{asString(value)}</span>
  }
}

"use client"

import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { cn } from "@/lib/utils"
import type { DisplayMode, ImageSize } from "../types/column.types"

function getImageSizeClass(size: ImageSize = "md"): string {
  switch (size) {
    case "sm":
      return "size-7"
    case "lg":
      return "size-12"
    case "xl":
      return "size-16"
    case "md":
    default:
      return "size-9"
  }
}

interface ImageCellProps<TData extends Record<string, unknown>> {
  row: TData
  imageKey: keyof TData & string
  altKey?: keyof TData & string
  displayMode?: DisplayMode
  imageSize?: ImageSize
}

export function ImageCell<TData extends Record<string, unknown>>({
  row,
  imageKey,
  altKey,
  displayMode = "avatar",
  imageSize,
}: ImageCellProps<TData>) {
  const src = (row[imageKey] ?? "") as string
  const alt = (altKey ? (row[altKey] as string | undefined) : undefined) ?? ""
  const sizeClass = getImageSizeClass(imageSize)

  if (displayMode === "avatar") {
    return (
      <Avatar className={sizeClass}>
        <AvatarImage src={src} alt={alt} />
        <AvatarFallback>{alt?.[0] ?? "?"}</AvatarFallback>
      </Avatar>
    )
  }

  const radius =
    displayMode === "rounded"
      ? "rounded-full"
      : displayMode === "square"
        ? "rounded-md"
        : ""

  return (
    <div className={cn("overflow-hidden", sizeClass, radius)}>
      {/* eslint-disable-next-line @next/next/no-img-element */}
      <img
        src={src}
        alt={alt}
        className={cn("h-full w-full object-cover", radius)}
      />
    </div>
  )
}

"use client";

import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";

interface SelectOption {
  label: string;
  value: unknown;
}

interface SelectCellProps {
  value: unknown;
  options: SelectOption[];
  onChange: (value: unknown) => void;
}

export function SelectCell({ value, options, onChange }: SelectCellProps) {
  const stringValue =
    value === null || value === undefined ? undefined : String(value);

  return (
    <Select defaultValue={stringValue} onValueChange={(v) => onChange(v)}>
      <SelectTrigger className="h-8 w-full">
        <SelectValue placeholder="Select..." />
      </SelectTrigger>
      <SelectContent className="border border-input/60 shadow-sm rounded-md">
        {options.map((opt) => (
          <SelectItem key={String(opt.value)} value={String(opt.value)}>
            {opt.label}
          </SelectItem>
        ))}
      </SelectContent>
    </Select>
  );
}

"use client"

import * as React from "react"
import { CheckIcon, PlusCircleIcon } from "lucide-react"
import { Column } from "@tanstack/react-table"
import { cn } from "@/lib/utils"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
  CommandSeparator,
} from "@/components/ui/command"
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover"
import { Separator } from "@/components/ui/separator"

interface DataTableFacetedFilterProps<TData, TValue> {
  column?: Column<TData, TValue>
  title?: string
  options: {
    label: string
    value: string
    icon?: React.ComponentType<{ className?: string }>
  }[]
}

export function DataTableFacetedFilter<TData, TValue>({
  column,
  title,
  options,
}: DataTableFacetedFilterProps<TData, TValue>) {
  const facets = column?.getFacetedUniqueValues()
  const selectedValues = new Set(column?.getFilterValue() as string[])

  return (
    <Popover>
      <PopoverTrigger asChild>
        <Button variant="outline" size="sm" className="h-9 border-dashed">
          <PlusCircleIcon className="mr-2 h-4 w-4" />
          {title}
          {selectedValues?.size > 0 && (
            <>
              <Separator orientation="vertical" className="mx-2 h-4" />
              <Badge variant="secondary" className="rounded-sm px-1 font-normal lg:hidden">
                {selectedValues.size}
              </Badge>
              <div className="hidden space-x-1 lg:flex">
                {selectedValues.size > 2 ? (
                  <Badge variant="secondary" className="rounded-sm px-1 font-normal">
                    {selectedValues.size} selected
                  </Badge>
                ) : (
                  options
                    .filter((option) => selectedValues.has(option.value))
                    .map((option) => (
                      <Badge variant="secondary" key={option.value} className="rounded-sm px-1 font-normal">
                        {option.label}
                      </Badge>
                    ))
                )}
              </div>
            </>
          )}
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-50 p-0" align="start">
        <Command>
          <CommandInput placeholder={title} />
          <CommandList>
            <CommandEmpty>No results found.</CommandEmpty>
            <CommandGroup>
              {options.map((option) => {
                const isSelected = selectedValues.has(option.value)
                return (
                  <CommandItem
                    key={option.value}
                    onSelect={() => {
                      if (isSelected) {
                        selectedValues.delete(option.value)
                      } else {
                        selectedValues.add(option.value)
                      }
                      const filterValues = Array.from(selectedValues)
                      column?.setFilterValue(filterValues.length ? filterValues : undefined)
                    }}
                  >
                    <div
                      className={cn(
                        "mr-2 flex h-4 w-4 items-center justify-center rounded-sm border border-primary",
                        isSelected ? "bg-primary text-primary-foreground" : "opacity-50 [&_svg]:invisible"
                      )}
                    >
                      <CheckIcon className={cn("h-4 w-4")} />
                    </div>
                    {option.icon && <option.icon className="mr-2 h-4 w-4 text-muted-foreground" />}
                    <span>{option.label}</span>
                    {facets?.get(option.value) && (
                      <span className="ml-auto flex h-4 w-4 items-center justify-center font-mono text-xs">
                        {facets.get(option.value)}
                      </span>
                    )}
                  </CommandItem>
                )
              })}
            </CommandGroup>
            {selectedValues.size > 0 && (
              <>
                <CommandSeparator />
                <CommandGroup>
                  <CommandItem
                    onSelect={() => column?.setFilterValue(undefined)}
                    className="justify-center text-center"
                  >
                    Clear filters
                  </CommandItem>
                </CommandGroup>
              </>
            )}
          </CommandList>
        </Command>
      </PopoverContent>
    </Popover>
  )
}

"use client"

import { Button } from "@/components/ui/button"
import { GripVerticalIcon } from "lucide-react"
import { useRowDrag } from "./row-drag-context"

export function DragHandle() {
  const { attributes, listeners, isDragging } = useRowDrag()

  // Only render if listeners exist (i.e., we are inside a draggable row)
  if (!listeners) {
    return null
  }

  return (
    <Button
      {...attributes}
      {...listeners}
      variant="ghost"
      size="icon"
      className="h-8 w-8 cursor-grab text-muted-foreground hover:bg-transparent active:cursor-grabbing"
      style={{ 
        cursor: isDragging ? "grabbing" : "grab",
        opacity: isDragging ? 0.5 : 1 
      }}
    >
      <GripVerticalIcon className="size-4" />
      <span className="sr-only">Drag row</span>
    </Button>
  )
}

"use client"

import * as React from "react"
import { TableCell, TableRow } from "@/components/ui/table"
import { cn } from "@/lib/utils"
import { useSortable } from "@dnd-kit/sortable"
import { CSS } from "@dnd-kit/utilities"
import type { Cell, Row } from "@tanstack/react-table"
import { flexRender } from "@tanstack/react-table"
import { RowDragProvider } from "./row-drag-context"

interface DraggableRowProps<TData> {
  row: Row<TData>
  densityClass: string
}

function DraggableRowComponent<TData>({
  row,
  densityClass,
}: DraggableRowProps<TData>) {
  const {
    transform,
    transition,
    setNodeRef,
    isDragging,
    attributes,
    listeners,
  } = useSortable({
    id: row.id,
  })

  // Remove the problematic aria-describedby attribute
  const filteredAttributes = React.useMemo(() => {
    return Object.fromEntries(
      Object.entries(attributes).filter(([key]) => key !== "aria-describedby")
    )
  }, [attributes])

  // CSS.Translate is more performant for GPU composition than CSS.Transform
  const style: React.CSSProperties = {
    transform: CSS.Translate.toString(transform),
    transition,
    zIndex: isDragging ? 10 : 1,
    position: "relative",
  }

  // Memoize context to prevent unnecessary provider updates
  const contextValue = React.useMemo(
    () => ({ attributes: filteredAttributes, listeners, isDragging }),
    [filteredAttributes, listeners, isDragging]
  )

  return (
    <RowDragProvider value={contextValue}>
      <TableRow
        ref={setNodeRef}
        data-state={row.getIsSelected() && "selected"}
        data-dragging={isDragging}
        className={cn(
          "data-[dragging=true]:opacity-50 data-[dragging=true]:bg-muted/50",
          densityClass,
        )}
        style={style}
      >
        {row
          .getVisibleCells()
          .map((cell: Cell<TData, unknown>) => (
            <TableCell key={cell.id}>
              {flexRender(
                cell.column.columnDef.cell,
                cell.getContext(),
              )}
            </TableCell>
          ))}
      </TableRow>
    </RowDragProvider>
  )
}

// Custom Comparator: This prevents the row from re-rendering if its 
// specific data hasn't changed, even if the parent table updates.
function arePropsEqual<TData>(
  prev: DraggableRowProps<TData>,
  next: DraggableRowProps<TData>,
) {
  // 1. Check if density changed
  if (prev.densityClass !== next.densityClass) return false

  // 2. Check if underlying data changed (Referential equality check)
  // This works because we update data immutably in the parent
  if (prev.row.original !== next.row.original) return false

  // 3. Check if selection state changed
  if (prev.row.getIsSelected() !== next.row.getIsSelected()) return false

  // 4. Note: We don't need to check isDragging here because useSortable 
  // inside the component handles that state locally.
  
  return true
}

// Export the Memoized Component
export const DraggableRow = React.memo(
  DraggableRowComponent,
  arePropsEqual,
) as typeof DraggableRowComponent

"use client"

import * as React from "react"
import {
  DndContext,
  closestCenter,
  KeyboardSensor,
  MouseSensor,
  TouchSensor,
  useSensor,
  useSensors,
  type DragEndEvent,
  type UniqueIdentifier,
} from "@dnd-kit/core"
import { restrictToVerticalAxis } from "@dnd-kit/modifiers"
import {
  SortableContext,
  arrayMove,
  verticalListSortingStrategy,
} from "@dnd-kit/sortable"
import {
  type ColumnFiltersState,
  getCoreRowModel,
  getFacetedRowModel,
  getFacetedUniqueValues,
  getFilteredRowModel,
  getPaginationRowModel,
  getSortedRowModel,
  type SortingState,
  type VisibilityState,
  type RowSelectionState,
  useReactTable,
  flexRender,
  type ColumnDef,
} from "@tanstack/react-table"
import {
  Table,
  TableBody,
  TableHeader,
  TableHead,
  TableRow,
  TableCell,
} from "@/components/ui/table"
import { Tabs, TabsContent } from "@/components/ui/tabs"
import { Checkbox } from "@/components/ui/checkbox"
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu"
import { Button } from "@/components/ui/button"
import { cn } from "@/lib/utils"
import { ArrowDownIcon, ArrowUpIcon, ArrowUpDownIcon, EllipsisVerticalIcon } from "lucide-react"

import type { DynamicDataTableProps, ViewMode } from "../types/table.types"
import type { DynamicColumnDef } from "../types/column.types"
import { ImageCell } from "../cells/image-cell"
import { EditableCell } from "../cells/editable-cell"
import { DragHandle } from "./drag-handle"
import { DraggableRow } from "./draggable-row"
import { TableToolbar } from "./table-toolbar"
import { TableFooter } from "./table-footer"

// --- HELPER FOR NESTED UPDATES ---
function setNestedValue<T extends Record<string, unknown>>(obj: T, path: string, value: unknown): T {
  const newObj = structuredClone(obj)
  const keys = path.split(".")
  let current: Record<string, unknown> = newObj

  for (let i = 0; i < keys.length - 1; i++) {
    const key = keys[i]
    if (!current[key]) {
      current[key] = {}
    }
    current = current[key] as Record<string, unknown>
  }

  current[keys[keys.length - 1]] = value
  return newObj
}

interface ExtendedDataTableProps<TData extends Record<string, unknown>>
  extends DynamicDataTableProps<TData> {
  onSave?: (data: TData[]) => void
  onDeleteSelected?: (selectedRows: TData[]) => void
  isLoading?: boolean
}

export function DynamicDataTable<TData extends Record<string, unknown>>(
  props: ExtendedDataTableProps<TData>
) {
  const {
    data: initialData,
    columnConfig,
    rowIdKey,
    enableRowSelection = false,
    enableRowDrag = false,
    enableColumnVisibility = true,
    enableGlobalFilter = true,
    viewMode: initialViewMode = "comfortable",
    toolbarTitle,
    toolbarSubtitle,
    onViewRow,
    onEditRow,
    onDeleteRow,
    onDataChange,
    onAddRow,
    onSave,
    onDeleteSelected,
    isLoading = false,
  } = props

  // -- STATE --
  const [data, setData] = React.useState<TData[]>(() => initialData)
  const [originalData, setOriginalData] = React.useState<TData[]>(() => initialData)
  const [viewMode, setViewMode] = React.useState<ViewMode>(initialViewMode)
  const isInternalChange = React.useRef(false)

  const [rowSelection, setRowSelection] = React.useState<RowSelectionState>({})
  const [columnVisibility, setColumnVisibility] = React.useState<VisibilityState>({})
  const [columnFilters, setColumnFilters] = React.useState<ColumnFiltersState>([])
  const [sorting, setSorting] = React.useState<SortingState>([])
  const [pagination, setPagination] = React.useState({ pageIndex: 0, pageSize: 10 })
  const [globalFilter, setGlobalFilter] = React.useState<string>("")

  const sensors = useSensors(
    useSensor(MouseSensor, {}),
    useSensor(TouchSensor, {}),
    useSensor(KeyboardSensor, {})
  )

  const densityClass = React.useMemo(() => getDensityClass(viewMode), [viewMode])

  // -- EFFECTS --
  React.useEffect(() => {
    if (isInternalChange.current) {
      isInternalChange.current = false
      return
    }
    setData(initialData)
    setOriginalData(initialData)
  }, [initialData])

  const hasUnsavedChanges = React.useMemo(() => {
    return JSON.stringify(data) !== JSON.stringify(originalData)
  }, [data, originalData])

  // -- HANDLERS --
  const updateCell = React.useCallback(
    (rowId: string | number, accessorKey: keyof TData & string, value: unknown) => {
      isInternalChange.current = true
      const nextData = data.map((row) => {
        if (String(row[rowIdKey]) === String(rowId)) {
          if (accessorKey.includes(".")) {
            return setNestedValue(row, accessorKey, value)
          }
          return { ...row, [accessorKey]: value }
        }
        return row
      })
      setData(nextData)
      if (onDataChange) onDataChange(nextData)
    },
    [data, onDataChange, rowIdKey]
  )

  const handleBatchDelete = React.useCallback(() => {
    if (!onDeleteSelected) return
    isInternalChange.current = true
    const selectedIds = new Set(Object.keys(rowSelection))
    const rowsToDelete = data.filter((row) => selectedIds.has(String(row[rowIdKey])))
    const nextData = data.filter((row) => !selectedIds.has(String(row[rowIdKey])))
    onDeleteSelected(rowsToDelete)
    onDataChange?.(nextData)
    setData(nextData)
    setOriginalData(nextData)
    setRowSelection({})
  }, [data, rowSelection, onDeleteSelected, onDataChange, rowIdKey])

  const handleSave = React.useCallback(() => {
    onSave?.(data)
    setOriginalData(data)
  }, [data, onSave])


  const dataIds = React.useMemo<UniqueIdentifier[]>(
    () => data.map((row) => String(row[rowIdKey])),
    [data, rowIdKey]
  )

  const columns = React.useMemo(
    () =>
      buildColumns<TData>({
        columnConfig,
        enableRowDrag,
        enableRowSelection,
        onViewRow,
        onEditRow,
        onDeleteRow,
        rowIdKey,
        updateCell,
      }),
    [columnConfig, enableRowDrag, enableRowSelection, onViewRow, onEditRow, onDeleteRow, rowIdKey, updateCell]
  )

  const defaultColumn = React.useMemo<Partial<ColumnDef<TData, unknown>>>(
    () => ({ minSize: 50, maxSize: 500 }), []
  )

  // eslint-disable-next-line react-hooks/incompatible-library
  const table = useReactTable<TData>({
    data,
    columns,
    defaultColumn,
    state: { sorting, columnVisibility, rowSelection, columnFilters, pagination, globalFilter },
    getRowId: (row) => String(row[rowIdKey]),
    enableRowSelection,
    filterFromLeafRows: true,
    autoResetPageIndex: false,
    onRowSelectionChange: setRowSelection,
    onSortingChange: setSorting,
    onColumnFiltersChange: setColumnFilters,
    onColumnVisibilityChange: setColumnVisibility,
    onPaginationChange: setPagination,
    onGlobalFilterChange: (val) => setGlobalFilter(String(val ?? "")),
    getCoreRowModel: getCoreRowModel<TData>(),
    getFilteredRowModel: getFilteredRowModel<TData>(),
    getPaginationRowModel: getPaginationRowModel<TData>(),
    getSortedRowModel: getSortedRowModel<TData>(),
    getFacetedRowModel: getFacetedRowModel<TData>(),
    getFacetedUniqueValues: getFacetedUniqueValues<TData>(),
  })

  const handleExport = React.useCallback(() => {
    const exportableColumns = table.getVisibleFlatColumns().filter(
      (col) =>
        col.id !== "__select__" &&
        col.id !== "__drag__" &&
        col.id !== "__actions__"
    )
    const headers = exportableColumns.map((col) => {
      const headerVal = col.columnDef.header
      return typeof headerVal === "string" ? headerVal : col.id
    })
    const rows = table.getFilteredRowModel().rows.map((row) =>
      exportableColumns
        .map((col) => {
          const val = row.getValue(col.id)
          let cellData = ""
          if (val instanceof Date) {
             cellData = val.toISOString()
          } else if (typeof val === 'object' && val !== null) {
             cellData = JSON.stringify(val)
          } else {
             cellData = String(val ?? "")
          }
          return `"${cellData.replace(/"/g, '""')}"`
        })
        .join(",")
    )
    const csvContent = [headers.join(","), ...rows].join("\n")
    const blob = new Blob([csvContent], { type: "text/csv;charset=utf-8;" })
    const url = URL.createObjectURL(blob)
    const link = document.createElement("a")
    link.setAttribute("href", url)
    link.setAttribute("download", `export_${new Date().toISOString().split('T')[0]}.csv`)
    document.body.appendChild(link)
    link.click()
    document.body.removeChild(link)
    URL.revokeObjectURL(url)
  }, [table])

  const handleDragEnd = (event: DragEndEvent): void => {
    if (!enableRowDrag) return
    const { active, over } = event
    if (!over || active.id === over.id) return
    isInternalChange.current = true
    const oldIndex = data.findIndex((item) => String(item[rowIdKey]) === active.id)
    const newIndex = data.findIndex((item) => String(item[rowIdKey]) === over.id)
    if (oldIndex === -1 || newIndex === -1) return
    const nextData = arrayMove(data, oldIndex, newIndex)
    setData(nextData)
    if (onDataChange) onDataChange(nextData)
  }

  // Define utility columns to remove padding from
  const utilityCols = ["__select__", "__drag__", "__actions__"]

  return (
    <Tabs defaultValue="table" className="flex w-full flex-col gap-4">
      <TableToolbar
        table={table}
        columnConfig={columnConfig}
        enableGlobalFilter={enableGlobalFilter}
        globalFilter={globalFilter}
