  }

  // 4. Add Row
  const handleAddRow = () => {
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name: "New Member",
      email: "new@example.com",
      image: "",
      role_id: "role_user",
      role: { name: "User", description: "Regular user" },
      email_verified: false,
      created_at: new Date().toISOString(),
    }
    setData([newUser, ...data])
  }

  return (
    <div className="container mx-auto py-10">
      <div className="rounded-xl border bg-card shadow-sm">
        <DynamicDataTable<User>
          data={data}
          columnConfig={columns}
          rowIdKey="id"
          
          // Layout Config
          toolbarTitle="User Management"
          toolbarSubtitle="View and manage system access and permissions."
          
          // Features
          enableRowDrag
          enableRowSelection
          enableColumnVisibility
          enableGlobalFilter
          viewMode="comfortable"
          isLoading={false}
          
          
          // Events
          onSave={handleSave}
          onDeleteSelected={handleDeleteSelected}
          onAddRow={handleAddRow} // Toolbar "Add" button
          onViewRow={handleView}
          onEditRow={handleEdit}
          onDeleteRow={handleDelete}
        />
      </div>

      {/* Debug: View Raw Data */}
      <div className="mt-8 rounded bg-slate-950 p-4 text-xs text-slate-50 font-mono">
        <p className="mb-2 font-bold text-green-400">Current Data State:</p>
        <pre>{JSON.stringify(data.map(u => ({ name: u.name, role: u.role.name, verified: u.email_verified })), null, 2)}</pre>
      </div>
    </div>
  )
}
